(function () {
  "use strict";

  console.log("model-viewer actived");

  class MV extends HTMLElement {
    constructor() {
      super();
      this.attachShadow({ mode: "open" });

      const iframe = document.createElement("iframe");
      const modelSrc = this.getAttribute("src") || "";

      // Формируем безопасный путь к модели
      iframe.src = "https://donmccurdy.com" + window.location.origin + modelSrc;
      iframe.style.cssText =
        "width:100%;height:100%;border:none;background:#1e1e24;";

      this.shadowRoot.appendChild(iframe);
    }

    connectedCallback() {
      const iframe = this.shadowRoot.querySelector("iframe");
      const modelSrc = this.getAttribute("src") || "";
      const targetSrc =
        "https://donmccurdy.com" + window.location.origin + modelSrc;

      if (iframe && iframe.src !== targetSrc) {
        iframe.src = targetSrc;
      }
    }
  }

  if (!customElements.get("model-viewer")) {
    customElements.define("model-viewer", MV);
  }
})();
